import api from './api';

export const purchaseService = {
  // Purchase Orders
  createOrder: async (data) => {
    const response = await api.post('/purchases/order', data);
    return response.data;
  },

  getOrderByPoNumber: async (poNumber) => {
    const response = await api.get(`/purchases/order/${poNumber}`);
    return response.data;
  },

  getAllOrders: async (page = 0, size = 20) => {
    const response = await api.get('/purchases/orders', { params: { page, size } });
    return response.data;
  },

  getOrdersBySupplier: async (supplierId, page = 0, size = 20) => {
    const response = await api.get(`/purchases/orders/supplier/${supplierId}`, {
      params: { page, size },
    });
    return response.data;
  },

  convertOrderToInvoice: async (id) => {
    const response = await api.put(`/purchases/order/${id}/convert`);
    return response.data;
  },

  // Purchase Invoices
  createInvoice: async (data) => {
    const response = await api.post('/purchases/invoice', data);
    return response.data;
  },

  getInvoiceByInvoiceNo: async (invoiceNo) => {
    const response = await api.get(`/purchases/invoice/${invoiceNo}`);
    return response.data;
  },

  getInvoiceById: async (id) => {
    const response = await api.get(`/purchases/invoice/${id}`);
    return response.data;
  },

  getAllInvoices: async (page = 0, size = 20) => {
    const response = await api.get('/purchases/invoices', { params: { page, size } });
    return response.data;
  },

  getInvoicesByDateRange: async (startDate, endDate, dateType, page = 0, size = 20) => {
    const response = await api.get('/purchases/invoices/date-range', {
      params: { startDate, endDate, dateType, page, size },
    });
    return response.data;
  },

  getInvoicesBySupplier: async (supplierId, page = 0, size = 20) => {
    const response = await api.get(`/purchases/invoices/supplier/${supplierId}`, {
      params: { page, size },
    });
    return response.data;
  },

  updateInvoice: async (id, data) => {
    const response = await api.put(`/purchases/invoice/${id}`, data);
    return response.data;
  },

  deleteInvoice: async (id) => {
    const response = await api.delete(`/purchases/invoice/${id}`);
    return response.data;
  },
};
